import React from "react";
import { useAuth } from "../context/AuthContext";
export default function Profile() {
  const { user } = useAuth();
  return (
    <div className="space-y-5 animate-in max-w-2xl">
      <h1 className="page-title">My Profile</h1>
      <div className="card">
        <div className="flex items-center gap-4 mb-6 pb-6 border-b border-slate-100">
          <div className="w-16 h-16 rounded-2xl bg-gradient-to-br from-primary-400 to-purple-500 flex items-center justify-center text-white text-2xl font-bold">{(user?.email || "U")[0].toUpperCase()}</div>
          <div><p className="text-xl font-bold text-slate-900">{user?.email}</p><p className="text-slate-500 capitalize">{user?.role?.replace("_", " ")}</p></div>
        </div>
        <div className="grid grid-cols-2 gap-4 text-sm">
          {[["Role", user?.role?.replace("_"," ")],["Employee ID", user?.employeeId || "—"],["Status","Active"],["Last Login", user?.lastLogin ? new Date(user.lastLogin).toLocaleDateString() : "—"]].map(([k,v]) => (
            <div key={k}><p className="text-slate-400 text-xs">{k}</p><p className="font-medium text-slate-800 capitalize mt-0.5">{v || "—"}</p></div>
          ))}
        </div>
      </div>
    </div>
  );
}
